/**
 * Select applicable recommendations based on active risk flags.
 * Returns at most 4 recommendations to avoid overwhelming users.
 */
export function selectRecommendations(flags: PlanRiskFlags): Recommendation[] {
  const applicable = ALL_RECOMMENDATIONS.filter(
    (r) => flags[r.applicableWhen as keyof PlanRiskFlags] === true
  );
  // Deduplicate and limit to 4
  const seen = new Set<string>();
  const result: Recommendation[] = [];
  for (const rec of applicable) {
    if (!seen.has(rec.id)) {
      seen.add(rec.id);
      result.push(rec);
    }
    if (result.length >= 4) break;
  }
  return result;
}

/**
 * Format recommendations for inclusion in AI prompt.
 */
export function formatRecommendationsForPrompt(recs: Recommendation[]): string {
  if (recs.length === 0) return 'No specific recommendations flagged.';
  return recs
    .map(
      (r, i) =>
        `${i + 1}. ${r.suggestion}\n   Reason: ${r.reason}\n   Impact: ${r.potentialImpact}\n   Tradeoff: ${r.tradeoff}`
    )
    .join('\n\n');
}
